'use client';

import { useState } from 'react';
import { Link2, Copy, Check, Send, RefreshCw } from 'lucide-react';
import { useSession } from '@/hooks/useSession';

interface LinkItem {
  teacher: string;
  token: string;
  status: string;
}

export default function CollaborationPage() {
  const { sessionId, schoolData } = useSession();
  const [links, setLinks] = useState<LinkItem[]>([]);
  const [generating, setGenerating] = useState(false);
  const [copied, setCopied] = useState<string | null>(null);

  const teachers = ((schoolData as Record<string, unknown>)?.teachers as Record<string, unknown>[]) || [];

  const handleGenerate = async () => {
    if (!sessionId) return;
    setGenerating(true);
    // Placeholder — will call generateCollabLinks(sessionId) in Session 3
    setTimeout(() => {
      const placeholderLinks = teachers.map((t, i) => ({
        teacher: String((t as Record<string, unknown>).name || `Enseignant ${i + 1}`),
        token: `demo${i}${Math.random().toString(36).slice(2, 6)}`,
        status: 'non_envoye',
      }));
      setLinks(placeholderLinks);
      setGenerating(false);
    }, 600);
  };

  const copyLink = (token: string) => {
    const url = `${window.location.origin}/collab/${token}`;
    navigator.clipboard.writeText(url);
    setCopied(token);
    setTimeout(() => setCopied(null), 2000);
  };

  return (
    <div className="p-8 max-w-4xl mx-auto">
      {/* ── Header ───────────────────────────────────── */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">
            Collaboration
          </h1>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
            Générez des liens pour recueillir les disponibilités des
            enseignants.
          </p>
        </div>
        <button
          onClick={handleGenerate}
          disabled={generating || !teachers.length}
          className="inline-flex items-center gap-2 px-4 py-2.5 rounded-xl bg-gradient-to-r from-teal-600 to-emerald-600 text-white text-sm font-medium shadow-md shadow-teal-500/20 hover:shadow-lg hover:-translate-y-px disabled:opacity-40 transition-all"
        >
          {generating ? (
            <RefreshCw size={16} className="animate-spin" />
          ) : (
            <Link2 size={16} />
          )}
          Générer les liens
        </button>
      </div>

      {/* ── Empty state ──────────────────────────────── */}
      {!links.length && (
        <div className="flex flex-col items-center justify-center py-32 text-center">
          <div className="w-16 h-16 rounded-2xl bg-gray-100 dark:bg-gray-800 flex items-center justify-center mb-4">
            <Send size={24} className="text-gray-400" />
          </div>
          <h2 className="text-lg font-semibold text-gray-700 dark:text-gray-300 mb-2">
            Prêt pour la collaboration
          </h2>
          <p className="text-sm text-gray-400 dark:text-gray-500 max-w-md">
            {teachers.length
              ? `${teachers.length} enseignants configurés. Cliquez "Générer les liens" pour créer un formulaire unique pour chacun.`
              : 'Ajoutez d\'abord les enseignants dans l\'espace de travail.'}
          </p>
        </div>
      )}

      {/* ── Links table ──────────────────────────────── */}
      {links.length > 0 && (
        <div className="bg-white dark:bg-gray-900 rounded-2xl border border-gray-100 dark:border-gray-800 shadow-sm overflow-hidden">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-gray-100 dark:border-gray-800">
                <th className="text-left font-medium text-gray-500 dark:text-gray-400 px-5 py-3 text-xs uppercase tracking-wide">
                  Enseignant
                </th>
                <th className="text-left font-medium text-gray-500 dark:text-gray-400 px-5 py-3 text-xs uppercase tracking-wide">
                  Statut
                </th>
                <th className="text-right font-medium text-gray-500 dark:text-gray-400 px-5 py-3 text-xs uppercase tracking-wide">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody>
              {links.map((link) => (
                <tr
                  key={link.token}
                  className="border-b border-gray-50 dark:border-gray-800/50 hover:bg-gray-50 dark:hover:bg-gray-800/30 transition-colors"
                >
                  <td className="px-5 py-3 font-medium text-gray-700 dark:text-gray-300">
                    {link.teacher}
                  </td>
                  <td className="px-5 py-3">
                    <span
                      className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium ${
                        link.status === 'submitted'
                          ? 'bg-green-50 dark:bg-green-900/30 text-green-700 dark:text-green-400'
                          : 'bg-gray-100 dark:bg-gray-800 text-gray-500 dark:text-gray-400'
                      }`}
                    >
                      <span
                        className={`w-1.5 h-1.5 rounded-full ${
                          link.status === 'submitted'
                            ? 'bg-green-500'
                            : 'bg-gray-400'
                        }`}
                      />
                      {link.status === 'submitted' ? 'Soumis' : 'Non envoyé'}
                    </span>
                  </td>
                  <td className="px-5 py-3 text-right">
                    <button
                      onClick={() => copyLink(link.token)}
                      className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium border border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors"
                    >
                      {copied === link.token ? (
                        <>
                          <Check size={13} className="text-green-500" />
                          Copié !
                        </>
                      ) : (
                        <>
                          <Copy size={13} />
                          Copier le lien
                        </>
                      )}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
